import{_ as a,o as l,i as o,aZ as i}from"./chunks/framework.D08fXB_e.js";const h=JSON.parse('{"title":"oc-i18n-manager","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills/oc-i18n-manager.md","filePath":"guide/skills/oc-i18n-manager.md"}'),c={name:"guide/skills/oc-i18n-manager.md"};function n(s,e,d,t,r,p){return l(),o("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/skills/oc-i18n-manager.md for this page in Markdown format</div><h1 id="oc-i18n-manager" tabindex="-1">oc-i18n-manager <a class="header-anchor" href="#oc-i18n-manager" aria-label="Permalink to “oc-i18n-manager”">​</a></h1><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h2><ul><li>给菜单配置、窗口标题、窗口内业务页面、框架组件文案添加或维护翻译</li><li>工具栏语言切换、新增语言包</li><li>检查缺失翻译</li><li>维护应用 <code>src/locales</code>、<code>src/menu</code>、api fake menu 数据、<code>defineWindow</code> 标题、<code>useI18n</code>、<code>i18n.global.t</code>、SFC 内联 <code>&lt;i18n&gt;</code> 块</li></ul><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to “使用方式”">​</a></h2><p>直接说明以下信息即可：</p><ul><li>目标应用，例如 <code>example</code></li><li>要添加 / 维护哪些文案，或要做哪类操作（新增翻译、检查缺失、加语言、开语言切换器）</li></ul><p>示例：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>在 example 应用里给「报表」菜单和窗口标题加上中英繁三语翻译，</span></span>
<span class="line"><span>并在报表页面内加上「导出」按钮的内联文案。</span></span></code></pre></div><h2 id="文案归属" tabindex="-1">文案归属 <a class="header-anchor" href="#文案归属" aria-label="Permalink to “文案归属”">​</a></h2><p>技能会按使用范围决定文案位置：</p><ul><li>菜单项、窗口标题、页面头部标题 → <code>locales/lang/menu/*.json</code></li><li>某个窗口页面内部专用文案 → 该 <code>.vue</code> 的 <code>&lt;i18n lang=&quot;yaml&quot;&gt;</code></li><li>多个业务页面共享文案 → 对应业务模块的全局 JSON</li><li>公共框架组件、工具栏、舞台、账号、登录等文案 → <code>packages/locales/lang/app/**/*.json</code></li><li>单应用覆盖公共 <code>app.*</code> 文案 → <code>apps/&lt;app&gt;/src/locales/lang/app/**/*.json</code></li></ul><h2 id="结果" tabindex="-1">结果 <a class="header-anchor" href="#结果" aria-label="Permalink to “结果”">​</a></h2><p>根据需求通常会修改：</p><ul><li><code>apps/&lt;app&gt;/src/locales/lang/menu/*.json</code></li><li><code>packages/locales/lang/app/**/*.json</code></li><li><code>apps/&lt;app&gt;/src/locales/lang/app/**/*.json</code>（仅单应用覆盖或补充）</li><li><code>apps/&lt;app&gt;/src/views/windows/**/*.vue</code>（<code>&lt;i18n&gt;</code> 块或 <code>defineWindow</code> 标题）</li><li><code>apps/&lt;app&gt;/src/menu/**/*.ts</code></li><li>启用语言切换器时会修改 <code>apps/&lt;app&gt;/src/settings.ts</code>（遵循 <code>oc-framework-settings</code> 规则）</li></ul><blockquote><p>关键约束：修改全局 JSON 时所有语言文件必须同步，不要只更新 <code>zh-cn</code>；全局新增语言必须同步 <code>packages/locales/src/index.ts</code> 的 <code>defaultLocalesInfo</code>，单应用新增语言必须扩展应用侧 <code>localesInfo</code>。</p></blockquote>`,16)])])}const u=a(c,[["render",n]]);export{h as __pageData,u as default};
